example.code:
SELECT nombre FROM usuarios
ORDER BY edad DESC
LIMIT 3;

SELECT pais, COUNT(*)
FROM usuarios
GROUP BY pais;

SELECT ciudad, COUNT(*) AS total
FROM clientes
GROUP BY ciudad;

SELECT categoria, SUM(precio) AS ingresos_total
FROM pedidos
GROUP BY categoria;

SELECT departamento, AVG(salario) AS salario_promedio
FROM empleados
GROUP BY departamento;

SELECT pais, categoria, COUNT(*) AS total
FROM pedidos
GROUP BY pais, categoria;

SELECT c.nombre, p.total
FROM clientes c
LEFT JOIN pedidos p ON c.id = p.cliente_id;

